1394→int32_t riscv_nn_conv_HWC_s8_s8_s8_asym_bias_any_get_buffer_size(const uint16_t in_tensor_dim_x,
1395→                                                                 const uint16_t in_tensor_dim_y,
1396→                                                                 const uint16_t in_tensor_ch,
1397→                                                                 const uint16_t out_tensor_ch,
1398→                                                                 const uint16_t ker_dim_x,
1399→                                                                 const uint16_t ker_dim_y,
1400→                                                                 const uint16_t pad_x,
1401→                                                                 const uint16_t pad_y,
1402→                                                                 const uint16_t stride_x,
1403→                                                                 const uint16_t stride_y,
1404→                                                                 const uint16_t out_tensor_dim_x,
1405→                                                                 const uint16_t out_tensor_dim_y)
1406→{
1407→    (void) in_tensor_dim_x;
1408→    (void) in_tensor_dim_y;
1409→    (void) pad_x;
1410→    (void) pad_y;
1411→    (void) stride_x;
1412→    (void) stride_y;
1413→    (void) out_tensor_dim_x;
1414→    (void) out_tensor_dim_y;
1415→    int32_t buf_size = 0;
1416→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_TILING)
1417→    uint32_t buf_A = 0, buf_B = 0, buf_C = 0, buf_contri = 0;
1418→    const long align_byte = 64;
1419→    uint32_t tiling_size = 256;
1420→#ifdef DCACHE_SIZE
1421→    int i;
1422→    int tiling_size_arr[] = { 1,8,16,32,64,128,256,512,1024,2048 };
1423→    int max_tile_size_in_cache = sqrt(((DCACHE_SIZE) << 10) / (6 * sizeof(int8_t)));
1424→    for (i = 1; i < sizeof(tiling_size_arr) / sizeof(tiling_size_arr[0]); i++)
1425→    {
1426→        if (tiling_size_arr[i] > max_tile_size_in_cache)
1427→        {
1428→            tiling_size = tiling_size_arr[i - 1];
1429→            break;
1430→        }
1431→    }
1432→#endif
1433→    buf_A = tiling_size * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(int8_t); //tiling version
1434→    buf_A += align_byte - 1;
1435→    buf_B = out_tensor_ch * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(int8_t); //converted src2
1436→    buf_B += align_byte - 1;
1437→    buf_C = tiling_size * out_tensor_ch * sizeof(int32_t); //temp buffer for q31 tiling accumulator
1438→    buf_C += align_byte - 1;
1439→    buf_contri = out_tensor_ch * sizeof(int32_t); //contribution
1440→    buf_contri += align_byte - 1;
1441→    buf_size = buf_A + buf_B + buf_C + buf_contri;
1442→#elif (defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)) || (defined(ENA_DSP_ISA))
1443→    const long align_byte = sizeof(long);
1444→
1445→    // two col buffer
1446→    buf_size = 2 * in_tensor_ch * ker_dim_x * ker_dim_y * sizeof(int8_t);
1447→    buf_size += align_byte - 1;     //extra size for aligning
1448→
1449→    // buffer for extra contribution
1450→    buf_size += out_tensor_ch * sizeof(int32_t);
1451→    buf_size += align_byte - 1;     //extra size for aligning
1452→#else
1453→    (void)in_tensor_ch;
1454→    (void)out_tensor_ch;
1455→    (void)ker_dim_x;
1456→    (void)ker_dim_y;
1457→#endif
1458→    return buf_size;
1459→}
